ass:bounded-crossfit-nuisances.statement:
/-- A12 bounded cross-fit outcome regressions: `μ̂_a ∈ [-1,1]`. -/
def BoundedCrossfitNuisances (muHat0 muHat1 : ℕ → 𝒳 → ℝ) : Prop :=
  ∀ n x, muHat0 n x ∈ Set.Icc (-1 : ℝ) 1 ∧ muHat1 n x ∈ Set.Icc (-1 : ℝ) 1

